70	func (s *Service) GetAvailableHandsets(ctx context.Context, serviceID string) ([]handsetdb.Handset, error) {
71		if serviceID == "" {
72			return nil, fmt.Errorf("service_id is required: %w", terrors.ErrBadRequest)
73		}
74	
75		// If the customer already has an active contract on this service, return empty list
76		_, err := s.store.GetActiveContractForService(ctx, serviceID)
77		if err == nil {
78			tlog.WithAttribute("service_id", serviceID).
79				Info(ctx, "active contract exists, returning empty handset list")
80			return nil, nil
81		}
82		if !errors.Is(err, terrors.ErrNotFound) {
83			return nil, fmt.Errorf("failed to check active contract: %w", err)
84		}
85	
86		handsets, err := s.store.GetHandsets(ctx, true)
87		if err != nil {
88			return nil, fmt.Errorf("failed to get handsets: %w", err)
89		}
90	
91		tlog.WithAttribute("service_id", serviceID).
92			WithAttribute("count", fmt.Sprintf("%d", len(handsets))).
93			Info(ctx, "returning available handsets")
94	
95		return handsets, nil
96	}
