98	func (s *Service) GetContractByRequestID(ctx context.Context, requestID string) (*models.Contract, *handsetdb.Handset, error) {
99		if requestID == "" {
100			return nil, nil, fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
101		}
102	
103		contract, err := s.store.GetContractByRequestID(ctx, requestID)
104		if err != nil {
105			if errors.Is(err, terrors.ErrNotFound) {
106				return nil, nil, fmt.Errorf("contract not found for request_id: %w", terrors.ErrNotFound)
107			}
108			return nil, nil, fmt.Errorf("failed to get contract by request_id: %w", err)
109		}
110	
111		h := handsetFromContract(contract)
112		if !hasContractHandsetDetails(h) {
113			catalogueHandset, err := s.store.GetHandsetByID(ctx, contract.HandsetID)
114			if err != nil {
115				return nil, nil, fmt.Errorf("failed to get handset for contract: %w", err)
116			}
117			h = mergeHandsetDetails(h, *catalogueHandset)
118		}
119	
120		if !hasContractHandsetDetails(h) {
121			return nil, nil, fmt.Errorf("contract handset details are incomplete: %w", terrors.ErrFailedValidation)
122		}
123	
124		return contract, &h, nil
125	}
