143	func (s *Service) RequestHandsetForService(ctx context.Context, serviceID, customerID, handsetID string) (string, string, error) {
144		if serviceID == "" || customerID == "" || handsetID == "" {
145			return "", "", fmt.Errorf("service_id, customer_id, and handset_id are required: %w", terrors.ErrBadRequest)
146		}
147	
148		// Check service belongs to customer
149		servicesResp, err := s.myServicesClient.GetServices(ctx, &myservicesapi.GetServicesRequest{
150			CustomerId:   customerID,
151			IncludeEnded: true,
152		})
153		if err != nil {
154			return "", "", fmt.Errorf("failed to retrieve services for customer: %w", err)
155		}
156	
157		found := false
158		for _, svc := range servicesResp.Services {
159			if svc.GetMobileService() != nil && svc.GetMobileService().GetServiceId() == serviceID {
160				found = true
161				if svc.GetMobileService().GetState() != serviceevents.MobileService_LIVE {
162					return "", "", fmt.Errorf("service is not active: %w", terrors.ErrFailedValidation)
163				}
164				break
165			}
166		}
167		if !found {
168			return "", "", fmt.Errorf("service not found for customer: %w", terrors.ErrNotFound)
169		}
170	
171		// Check for existing active contract
172		_, err = s.store.GetActiveContractForService(ctx, serviceID)
173		if err == nil {
174			return "", "", fmt.Errorf("an active handset contract already exists for this service: %w", terrors.ErrFailedValidation)
175		}
176		if !errors.Is(err, terrors.ErrNotFound) {
177			return "", "", fmt.Errorf("failed to check active contract: %w", err)
178		}
179	
180		// Verify handset exists and is in stock
181		h, err := s.store.GetHandsetByID(ctx, handsetID)
182		if err != nil {
183			return "", "", fmt.Errorf("handset not found: %w", terrors.ErrNotFound)
184		}
185		if !h.Active {
186			return "", "", fmt.Errorf("handset is not active: %w", terrors.ErrFailedValidation)
187		}
188		if h.OutOfStock {
189			return "", "", fmt.Errorf("handset is out of stock: %w", terrors.ErrFailedValidation)
190		}
191	
192		// Fetch customer information from account-gateway
193		accountResp, err := s.accountClient.GetAccount(ctx, &accountgateway.GetAccountRequest{
194			AccountId: customerID,
195		})
196		if err != nil {
197			return "", "", fmt.Errorf("failed to retrieve account: %w", err)
198		}
199		if accountResp.GetAccount() == nil {
200			return "", "", fmt.Errorf("account response missing account data")
201		}
202	
203		now := time.Now()
204		contract := models.Contract{
205			ID:             uuid.New().String(),
206			ServiceID:      serviceID,
207			CustomerID:     customerID,
208			HandsetID:      handsetID,
209			HandsetName:    h.Name,
210			ContractPrice:  h.ContractPrice,
211			RetailPrice:    h.RetailPrice,
212			ContractMonths: h.ContractTerm,
213			RequestID:      uuid.New().String(),
214			Status:         models.ContractStatusPendingEligibility,
215			CreatedAt:      now,
216			UpdatedAt:      now,
217		}
218	
219		if err = s.store.CreateContract(ctx, contract); err != nil {
220			return "", "", fmt.Errorf("failed to create contract: %w", err)
221		}
222	
223		tlog.WithAttribute("service_id", contract.ServiceID).
224			WithAttribute("customer_id", contract.CustomerID).
225			WithAttribute("contract_id", contract.ID).
226			WithAttribute("request_id", contract.RequestID).
227			WithAttribute("handset_id", contract.HandsetID).
228			Info(ctx, "handset contract created")
229	
230		// Produce lifecycle event
231		if err := s.eventProducer.ProduceMobileHandsetContractRequestedSync(ctx, &serviceevents.MobileHandsetContractRequested{
232			ServiceId:  contract.ServiceID,
233			CustomerId: contract.CustomerID,
234			ContractId: contract.ID,
235			HandsetId:  contract.HandsetID,
236		}); err != nil {
237			tlog.WithError(err).
238				WithAttribute("contract_id", contract.ID).
239				Error(ctx, "failed to produce MobileHandsetContractRequested event")
240		}
241	
242		redirectURL, err := eligibilityRedirectURL(s.eligibilityProviderURL, contract.RequestID)
243		if err != nil {
244			return "", "", err
245		}
246	
247		return contract.RequestID, redirectURL, nil
248	}
