250	func (s *Service) EligibilityCallback(ctx context.Context, requestID string, callbackStatus string, bankAccountNumber string, bankTitle string) error {
251		if requestID == "" || callbackStatus == "" {
252			return fmt.Errorf("request_id and status are required: %w", terrors.ErrBadRequest)
253		}
254	
255		if callbackStatus != "approved" && callbackStatus != "declined" {
256			return fmt.Errorf("invalid status: %s, must be 'approved' or 'declined': %w", callbackStatus, terrors.ErrBadRequest)
257		}
258	
259		contract, err := s.store.GetContractByRequestID(ctx, requestID)
260		if err != nil {
261			return fmt.Errorf("failed to get contract: %w", err)
262		}
263	
264		// Only the first eligibility callback should move a contract out of pending.
265		if contract.Status != models.ContractStatusPendingEligibility {
266			tlog.WithAttribute("request_id", requestID).
267				WithAttribute("current_status", string(contract.Status)).
268				Info(ctx, "eligibility callback ignored, contract is not pending eligibility")
269			return nil
270		}
271	
272		if callbackStatus == "declined" {
273			if err := s.store.UpdateContractStatus(ctx, requestID, models.ContractStatusDeclined); err != nil {
274				return fmt.Errorf("failed to update contract status: %w", err)
275			}
276	
277			if err := s.eventProducer.ProduceMobileHandsetContractDeclinedSync(ctx, &serviceevents.MobileHandsetContractDeclined{
278				ServiceId:  contract.ServiceID,
279				CustomerId: contract.CustomerID,
280				ContractId: contract.ID,
281				HandsetId:  contract.HandsetID,
282			}); err != nil {
283				tlog.WithError(err).
284					WithAttribute("contract_id", contract.ID).
285					Error(ctx, "failed to produce MobileHandsetContractDeclined event")
286			}
287	
288			tlog.WithAttribute("request_id", requestID).
289				WithAttribute("contract_id", contract.ID).
290				Info(ctx, "eligibility declined")
291	
292			return nil
293		}
294	
295		// Approved: store bank details, update status, produce event
296		if bankAccountNumber != "" || bankTitle != "" {
297			if err := s.store.UpdateContractBankDetails(ctx, requestID, bankAccountNumber, bankTitle); err != nil {
298				return fmt.Errorf("failed to store bank details: %w", err)
299			}
300		}
301	
302		if err := s.store.UpdateContractStatus(ctx, requestID, models.ContractStatusEligibilityApproved); err != nil {
303			return fmt.Errorf("failed to update contract status: %w", err)
304		}
305	
306		if err := s.eventProducer.ProduceMobileHandsetContractApprovedSync(ctx, &serviceevents.MobileHandsetContractApproved{
307			ServiceId:      contract.ServiceID,
308			CustomerId:     contract.CustomerID,
309			ContractId:     contract.ID,
310			HandsetId:      contract.HandsetID,
311			HandsetName:    contract.HandsetName,
312			ContractPrice:  money(contract.ContractPrice),
313			RetailPrice:    money(contract.RetailPrice),
314			ContractMonths: contract.ContractMonths,
315		}); err != nil {
316			tlog.WithError(err).
317				WithAttribute("contract_id", contract.ID).
318				Error(ctx, "failed to produce MobileHandsetContractApproved event")
319		}
320	
321		tlog.WithAttribute("request_id", requestID).
322			WithAttribute("contract_id", contract.ID).
323			Info(ctx, "eligibility approved, contract awaiting loan processing")
324	
325		return nil
326	}
