335	func handsetFromContract(contract *models.Contract) handsetdb.Handset {
336		return handsetdb.Handset{
337			ID:            contract.HandsetID,
338			Name:          contract.HandsetName,
339			ContractPrice: contract.ContractPrice,
340			RetailPrice:   contract.RetailPrice,
341			ContractTerm:  contract.ContractMonths,
342		}
343	}
344	
345	func hasContractHandsetDetails(h handsetdb.Handset) bool {
346		return h.Name != "" &&
347			h.ContractPrice != "" &&
348			h.RetailPrice != "" &&
349			h.ContractTerm != ""
350	}
351	
352	func mergeHandsetDetails(contractHandset, catalogueHandset handsetdb.Handset) handsetdb.Handset {
353		if contractHandset.Name == "" {
354			contractHandset.Name = catalogueHandset.Name
355		}
356		if contractHandset.ContractPrice == "" {
357			contractHandset.ContractPrice = catalogueHandset.ContractPrice
358		}
359		if contractHandset.RetailPrice == "" {
360			contractHandset.RetailPrice = catalogueHandset.RetailPrice
361		}
362		if contractHandset.ContractTerm == "" {
363			contractHandset.ContractTerm = catalogueHandset.ContractTerm
364		}
365		return contractHandset
366	}
367	
368	func eligibilityRedirectURL(providerURL, requestID string) (string, error) {
369		u, err := url.Parse(providerURL)
370		if err != nil {
371			return "", fmt.Errorf("failed to parse eligibility provider URL: %w", err)
372		}
373	
374		query := u.Query()
375		query.Set("request_id", requestID)
376		u.RawQuery = query.Encode()
377	
378		return u.String(), nil
379	}
